type QueryResult = {
  data?: unknown;
  error?: FetchBaseQueryError;
};

function asRecord(value: unknown): Record<string, unknown> | null {
  return value && typeof value === "object" && !Array.isArray(value)
    ? (value as Record<string, unknown>)
    : null;
}

function asString(value: unknown): string | undefined {
  return typeof value === "string" && value.trim() ? value.trim() : undefined;
}

function asNumber(value: unknown): number | undefined {
  return typeof value === "number" && Number.isFinite(value)
    ? value
    : undefined;
}

function asArray(value: unknown): unknown[] {
  return Array.isArray(value) ? value : [];
}

function asBoolean(value: unknown): boolean | undefined {
  if (typeof value === "boolean") return value;
  if (typeof value === "string") {
    const normalized = value.trim().toLowerCase();
    if (["true", "1", "yes", "active"].includes(normalized)) return true;
    if (["false", "0", "no", "inactive"].includes(normalized)) return false;
  }
  if (typeof value === "number") {
    if (value === 1) return true;
    if (value === 0) return false;
  }
  return undefined;
}

function parseSession(data: unknown): SessionPayload {
  const parsed = parseAuthPayload(data);
  const root = asRecord(data);
  const roleFromRoot = asString(root?.role);

  const user: AuthUser | null = parsed.user
    ? {
        ...parsed.user,
        role: parsed.user.role || roleFromRoot,
      }
    : null;

  const tenant: AuthTenant | null = parsed.tenant ? { ...parsed.tenant } : null;

  return {
    user,
    tenant,
    token: parsed.token,
    refreshToken: parsed.refreshToken,
  };
}

function parseTenantProfile(data: unknown): TenantProfilePayload {
  const parsed = parseAuthPayload(data);
  const root = asRecord(data);
  const tenantRecord = asRecord(root?.tenant);
  const addressRecord = asRecord(tenantRecord?.address);
  const subscriptionRecord = asRecord(root?.subscription);
  const userRecord = asRecord(root?.user);

  const user: AuthUser | null = parsed.user
    ? {
        ...parsed.user,
        id:
          parsed.user.id ||
          asString(userRecord?.id) ||
          asString(userRecord?._id),
        name: parsed.user.name || asString(userRecord?.name),
        email: parsed.user.email || asString(userRecord?.email),
        whatsappNumber:
          parsed.user.whatsappNumber || asString(userRecord?.whatsappNumber),
        role: parsed.user.role || asString(root?.role),
      }
    : null;

  const tenant: TenantProfilePayload["tenant"] = parsed.tenant
    ? {
        ...parsed.tenant,
        status: asString(tenantRecord?.status),
        contactNumber: asString(tenantRecord?.contactNumber) ?? null,
        email: asString(tenantRecord?.email) ?? asString(root?.email) ?? null,
        secondaryNumber: asString(tenantRecord?.secondaryNumber) ?? null,
        ownerName:
          asString(tenantRecord?.ownerName) ??
          asString(root?.ownerName) ??
          user?.name ??
          null,
        gstNumber: asString(tenantRecord?.gstNumber) ?? null,
        address: addressRecord
          ? {
              line1: asString(addressRecord.line1) ?? null,
              line2: asString(addressRecord.line2) ?? null,
              city: asString(addressRecord.city) ?? null,
              state: asString(addressRecord.state) ?? null,
              country: asString(addressRecord.country) ?? null,
              postalCode: asString(addressRecord.postalCode) ?? null,
            }
          : null,
      }
    : null;

  return {
    tenant,
    user,
    role: asString(root?.role),
    subscription: subscriptionRecord
      ? {
          planCode: asString(subscriptionRecord.planCode),
          status: asString(subscriptionRecord.status),
          startsAt: asString(subscriptionRecord.startsAt),
          endsAt: asString(subscriptionRecord.endsAt),
        }
      : null,
  };
}

function parseStaffMember(value: unknown): TenantStaffMember | null {
  const record = asRecord(value);
  if (!record) return null;

  const userRecord = asRecord(record.user);
  const membershipId =
    asString(record.membershipId) ||
    asString(record.id) ||
    asString(record._id);
  if (!membershipId) return null;

  return {
    membershipId,
    role: asString(record.role),
    isActive: asBoolean(record.isActive),
    user: {
      id: asString(userRecord?.id) || asString(userRecord?._id),
      name: asString(userRecord?.name),
      email: asString(userRecord?.email),
      whatsappNumber: asString(userRecord?.whatsappNumber),
      isActive: asBoolean(userRecord?.isActive),
    },
    raw: record,
  };
}

function parseStaffList(data: unknown): TenantStaffListPayload {
  const root = asRecord(data);
  const nestedData = asRecord(root?.data);
  const rawItems = asArray(root?.items).length
    ? root?.items
    : asArray(root?.staff).length
      ? root?.staff
      : asArray(nestedData?.items).length
        ? nestedData?.items
        : asArray(nestedData?.staff).length
          ? nestedData?.staff
          : [];
  const items = asArray(rawItems)
    .map(parseStaffMember)
    .filter((staff): staff is TenantStaffMember => Boolean(staff));
  return { items };
}

function parseStaffRoles(data: unknown): StaffRolesPayload {
  const root = asRecord(data);
  const nestedData = asRecord(root?.data);
  const rawRoles = asArray(root?.roles).length
    ? root?.roles
    : nestedData?.roles;
  const roles = asArray(rawRoles)
    .map((role) => asString(role))
    .filter((role): role is string => Boolean(role));
  return { roles };
}

function parseStaffMutation(
  data: unknown,
  fallbackMessage: string,
): TenantStaffMutationPayload {
  const root = asRecord(data);
  if (!root) {
    return { message: fallbackMessage };
  }

  return {
    message: asString(root.message) || fallbackMessage,
    staff:
      parseStaffMember(root.staff) ||
      parseStaffMember(root.data) ||
      parseStaffMember(root.member) ||
      null,
  };
}

function parseOrderItemsSummary(
  record: Record<string, unknown>,
): string | undefined {
  const itemsArray = asArray(record.items).concat(asArray(record.orderItems));
  if (!itemsArray.length) {
    return (
      asString(record.itemsText) || asString(record.itemsSummary) || undefined
    );
  }

  const parts = itemsArray
    .map((entry) => {
      const item = asRecord(entry);
      if (!item) return null;

      const name =
        asString(item.name) || asString(item.itemName) || asString(item.title);
      const quantity = asNumber(item.quantity) || asNumber(item.qty);

      if (!name) return null;
      return quantity && quantity > 1 ? `${name} x ${quantity}` : name;
    })
    .filter((value): value is string => Boolean(value));

  return parts.length ? parts.join(", ") : undefined;
}

function parseOrderRecord(value: unknown): OrderRecord | null {
  const record = asRecord(value);
  if (!record) return null;

  const tableRecord = asRecord(record.table);
  const customerRecord = asRecord(record.customer);

  const id =
    asString(record.id) ||
    asString(record._id) ||
    asString(record.orderId) ||
    asString(record.orderID) ||
    asString(record.orderNumber);

  if (!id) return null;

  const tableId =
    asString(record.tableId) ||
    asString(tableRecord?.id) ||
    asString(tableRecord?._id);
  const tableName =
    asString(record.tableName) ||
    asString(tableRecord?.name) ||
    asString(tableRecord?.tableName) ||
    (asNumber(tableRecord?.number)
      ? `Table ${asNumber(tableRecord?.number)}`
      : undefined);
  const customerName =
    asString(customerRecord?.name) || asString(customerRecord?.fullName);

  return {
    id,
    orderNumber: asString(record.orderNumber) || asString(record.displayId),
    status: asString(record.status) || "PLACED",
    tableId,
    tableName,
    sourceLabel: tableName
      ? `${tableName} - Dine-in`
      : customerName
        ? `${customerName} - Takeaway`
        : "Order",
    itemsSummary: parseOrderItemsSummary(record),
    items: [],
    subTotal: asNumber(record.subTotal),
    taxTotal: asNumber(record.taxTotal),
    grandTotal: asNumber(record.grandTotal),
    createdAt: asString(record.createdAt),
    updatedAt: asString(record.updatedAt),
    raw: record,
  };
}

function parseOrdersList(data: unknown): OrdersListPayload {
  const root = asRecord(data);
  const items = asArray(root?.items)
    .map(parseOrderRecord)
    .filter((item): item is OrderRecord => Boolean(item));
  const pagination = asRecord(root?.pagination);

  return {
    items,
    pagination: {
      page: asNumber(pagination?.page) || 1,
      limit: asNumber(pagination?.limit) || 20,
      total: asNumber(pagination?.total) || items.length,
      totalPages: asNumber(pagination?.totalPages) || 1,
    },
  };
}

function parseNumberMap(value: unknown): Record<string, number> {
  const record = asRecord(value);
  if (!record) return {};

  const output: Record<string, number> = {};
  Object.entries(record).forEach(([key, entry]) => {
    const parsed = asNumber(entry);
    if (parsed !== undefined) output[key] = parsed;
  });
  return output;
}

function parseDaySummary(value: unknown): ReportsSummaryPayload["days"][number] | null {
  const record = asRecord(value);
  if (!record) return null;

  const date = asString(record.date);
  if (!date) return null;

  return {
    date,
    day: asString(record.day) ?? "",
    label: asString(record.label) ?? date,
    orders: asNumber(record.orders) ?? 0,
    invoices: asNumber(record.invoices) ?? 0,
    paidInvoices: asNumber(record.paidInvoices) ?? 0,
    sales: asNumber(record.sales) ?? 0,
    expenses: asNumber(record.expenses) ?? 0,
    profit: asNumber(record.profit) ?? 0,
  };
}

function parseReportsSummary(data: unknown): ReportsSummaryPayload {
  const root = asRecord(data);
  const range = asRecord(root?.range);
  const thisMonth = asRecord(root?.thisMonth);
  const totals = asRecord(root?.totals);

  return {
    timezone: asString(root?.timezone) ?? "Asia/Kolkata",
    range: {
      type: asString(range?.type) ?? "unknown",
      from: asString(range?.from) ?? "",
      to: asString(range?.to) ?? "",
    },
    thisMonth: {
      month: asString(thisMonth?.month) ?? "",
      label: asString(thisMonth?.label) ?? "",
      orders: asNumber(thisMonth?.orders) ?? 0,
      invoices: asNumber(thisMonth?.invoices) ?? 0,
      paidInvoices: asNumber(thisMonth?.paidInvoices) ?? 0,
      sales: asNumber(thisMonth?.sales) ?? 0,
      expenses: asNumber(thisMonth?.expenses) ?? 0,
      profit: asNumber(thisMonth?.profit) ?? 0,
    },
    totals: {
      orders: asNumber(totals?.orders) ?? 0,
      invoices: asNumber(totals?.invoices) ?? 0,
      paidInvoices: asNumber(totals?.paidInvoices) ?? 0,
      sales: asNumber(totals?.sales) ?? 0,
      expenses: asNumber(totals?.expenses) ?? 0,
      profit: asNumber(totals?.profit) ?? 0,
    },
    days: asArray(root?.days)
      .map(parseDaySummary)
      .filter(
        (entry): entry is ReportsSummaryPayload["days"][number] => Boolean(entry),
      ),
  };
}

function isNotFound(error: FetchBaseQueryError | undefined): boolean {
  if (!error) return false;
  return error.status === 404;
}

async function postWithFallback(
  fetchWithBQ: (
    arg: string | FetchArgs,
  ) => QueryResult | PromiseLike<QueryResult>,
  endpoints: string[],
  body?: unknown,
): Promise<QueryResult> {
  let lastError: FetchBaseQueryError | undefined;

  for (const endpoint of endpoints) {
    const result = (await fetchWithBQ({
      url: endpoint,
      method: "POST",
      body,
      credentials: "include",
    })) as QueryResult;

    if (!result.error) {
      return result;
    }

    lastError = result.error;

    if (!isNotFound(result.error)) {
      return result;
    }
  }

  return { error: lastError };
}

async function requestWithFallback(
  fetchWithBQ: (
    arg: string | FetchArgs,
  ) => QueryResult | PromiseLike<QueryResult>,
  method: "PUT" | "PATCH" | "DELETE",
  endpoints: string[],
  body?: unknown,
): Promise<QueryResult> {
  let lastError: FetchBaseQueryError | undefined;

  for (const endpoint of endpoints) {
    const result = (await fetchWithBQ({
      url: endpoint,
      method,
      body,
      credentials: "include",
    })) as QueryResult;

    if (!result.error) {
      return result;
    }

    lastError = result.error;
    if (!isNotFound(result.error)) {
      return result;
    }
  }

  return { error: lastError };
}

function buildRefreshRequest(endpoint: string): FetchArgs {
  const stored = readStoredSession();
  const refreshToken = stored?.refreshToken || null;

  return {
    url: endpoint,
    method: "POST",
    credentials: "include",
    headers: refreshToken ? { "x-refresh-token": refreshToken } : undefined,
    body: refreshToken ? { refreshToken } : undefined,
  };
}

function buildLogoutRequest(endpoint: string): FetchArgs {
  const stored = readStoredSession();
  const refreshToken = stored?.refreshToken || null;

  return {
    url: endpoint,
    method: "POST",
    credentials: "include",
    headers: refreshToken ? { "x-refresh-token": refreshToken } : undefined,
    body: refreshToken ? { refreshToken } : undefined,
  };
}

