      ],
      async onCacheEntryAdded(
        _arg,
        { cacheDataLoaded, cacheEntryRemoved, dispatch, getState },
      ) {
        if (typeof window === "undefined") return;

        await cacheDataLoaded;

        const state = getState() as RootState;
        const token = state.auth.token;
        const tenantSlug = state.auth.tenant?.slug;
        const socketBaseUrl = RAW_API_BASE_URL.replace(/\/+$/, "").replace(
          /\/api$/,
          "",
        );

        const socket = io(socketBaseUrl, {
          withCredentials: true,
          transports: ["websocket", "polling"],
          auth: {
            token: token ? `Bearer ${token}` : undefined,
            tenantSlug,
          },
          query: tenantSlug ? { tenantSlug } : undefined,
        });

        const refreshOrders = () => {
          dispatch(
            authApi.util.invalidateTags([{ type: "Orders", id: "LIST" }]),
          );
        };

        const events = [
          "order:created",
          "order:updated",
          "order:deleted",
          "orders:updated",
          "order.created",
          "order.updated",
          "order.deleted",
        ] as const;

        events.forEach((eventName) => {
          socket.on(eventName, refreshOrders);
        });

        socket.on("connect", () => {
          if (tenantSlug) {
            socket.emit("tenant:join", { tenantSlug });
          }
        });

        await cacheEntryRemoved;
        events.forEach((eventName) => {
          socket.off(eventName, refreshOrders);
        });
        socket.disconnect();
      },
    }),

